import{_ as e,c as t,o as i,ae as a}from"./chunks/framework.DI6M9D4h.js";const b=JSON.parse('{"title":"Beangle WebMVC","description":"","frontmatter":{},"headers":[],"relativePath":"webmvc/index.md","filePath":"webmvc/index.md"}'),n={name:"webmvc/index.md"};function r(o,l,s,g,c,m){return i(),t("div",null,[...l[0]||(l[0]=[a('<h1 id="beangle-webmvc" tabindex="-1">Beangle WebMVC <a class="header-anchor" href="#beangle-webmvc" aria-label="Permalink to &quot;Beangle WebMVC&quot;">​</a></h1><p>Beangle WebMVC 是一个基于 Scala 的 MVC 框架，提供了简洁有力的 Web 应用开发能力，可替代 Struts 或 SpringMVC 等框架。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><p>Beangle WebMVC 提供以下核心能力：</p><ul><li><strong>基于 Command 的 MVC 架构</strong>：采用命令模式，提供清晰的控制器结构</li><li><strong>注解支持</strong>：通过注解配置 Action、参数绑定、视图等</li><li><strong>RESTful 支持</strong>：提供 REST 风格的路由和请求处理</li><li><strong>参数绑定</strong>：支持将请求参数自动绑定到方法参数</li><li><strong>Flash 参数</strong>：支持跨请求的参数传递</li><li><strong>视图管理</strong>：支持 Freemarker 等模板引擎，提供多种视图类型</li><li><strong>国际化</strong>：支持多语言资源和本地化</li><li><strong>拦截器</strong>：支持请求拦截和处理</li><li><strong>路由管理</strong>：提供灵活的路由配置和映射</li><li><strong>静态资源</strong>：支持静态资源的处理和管理</li><li><strong>CORS 支持</strong>：支持跨域资源共享</li><li><strong>缓存控制</strong>：支持响应缓存和结果缓存</li><li><strong>模块集结</strong>：支持将多个模块的 Action、标签等整合在一起</li><li><strong>异常处理</strong>：提供统一的异常处理机制</li><li><strong>配置管理</strong>：支持灵活的配置和定制</li></ul><h2 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h2><p>Beangle WebMVC 所提倡的惯例和用法包括：</p><ul><li>框架不应该从底层扫描class文件，这样不仅很慢，开发者也不能控制哪些action不进入框架。</li><li>框架应提供按照约定，指明符合哪些条件的Action/Controller是Command控制器(同时可以个别剃除)，而不是逐个通过xml定义。struts的struts-config.xml很强大，但是不采用模式匹配的情况下，配置逐个action及其result很繁琐。</li><li>框架应能在大部分场景下，不侵入用户代码。切换库的代码不能太大。Spring的各种Annotation虽然有助于类扫描，但是这种第三方库的耦合太强了。</li><li>拥有一定的模块集结能力，可以不用二次配置把各个jar包中的action、tag整合在一起。struts的plugin机制很好，springmvc中针对Controller可以按照模块扫描集结，但是针对非jsp的tag library支持不够。</li><li>应能提供restful的支持</li><li>Action/Contoller应能支持单例</li><li>应能支持参数绑定</li><li>应能支持flash参数闪存</li></ul><h2 id="文档组织" tabindex="-1">文档组织 <a class="header-anchor" href="#文档组织" aria-label="Permalink to &quot;文档组织&quot;">​</a></h2><ul><li><a href="/webmvc/usage.html">定义Action及其规则</a></li><li><a href="/webmvc/tags.html">WebUI标签</a></li><li><a href="/webmvc/tags.html">BeangleMVC内置标签</a></li><li><a href="/webmvc/api.html">API 调用说明</a> 详细的API使用指南，帮助开发者快速上手Beangle WebMVC框架</li></ul>',10)])])}const d=e(n,[["render",r]]);export{b as __pageData,d as default};
